import heapq
import math
class Solution:
    def pickGifts(self, gifts, k):
        heap = [-g for g in gifts]
        heapq.heapify(heap)
        for _ in range(k):
            largest = -heapq.heappop(heap)
            heapq.heappush(heap, -math.isqrt(largest))
        return -sum(heap)

