var pickGifts = function(gifts, k) {
    const arr = gifts.slice();
    for (let t = 0; t < k; t++) {
        let idx = 0;
        for (let i = 1; i < arr.length; i++) {
            if (arr[i] > arr[idx]) idx = i;
        }
        arr[idx] = Math.floor(Math.sqrt(arr[idx]));
    }
    return arr.reduce((a, b) => a + b, 0);
};
